// Enable the vstd array axioms (extensional equality + array_view ↔ index).
broadcast use vstd::array::group_array_axioms;

// (1) Materialize both =~= ensures as concrete Seq equalities through the
//     common witness `pre_self_.seq@.update(i as int, out)`.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq@ == pre_self_.seq@.update(i as int, out)
         && post2_self_.seq@ == pre_self_.seq@.update(i as int, out)));

// (2) Chain through the common target to get the seq view equality.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq@ =~= post2_self_.seq@));
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq@ == post2_self_.seq@));

// (3) Lift the Seq<A> equality to a Ghost<Seq<A>> equality on the `seq` field.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_.seq == post2_self_.seq));

// (4) Pointwise equality of the inline view, which is `seq@`.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (forall|j: int| 0 <= j < N as int
            ==> #[trigger] post1_self_@[j] == post2_self_@[j]));

// (5) Lift the pointwise view equality back to a full view equality (Seq
//     extensionality via =~=), giving the prover the trigger pattern
//     `post1_self_@ == post2_self_@`.
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_@ =~= post2_self_@));
assert(((post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
        && (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)))
    ==> (post1_self_@ == post2_self_@));

// (6) Generic struct-equality bridge: any two `Array<A, N>` values that agree
//     on the `seq` field and the `ar` field are structurally equal.  Verus
//     accepts this because struct equality is field-wise.
assert(forall|s1: Array<A, N>, s2: Array<A, N>|
    #![trigger s1 == s2]
    s1.seq == s2.seq && s1.ar == s2.ar ==> s1 == s2);

// (7) Symmetric ext-equal axiom for `[A; N]`: array equality is pointwise.
assert(forall|a1: [A; N], a2: [A; N]|
    #![trigger a1 == a2]
    (forall|j: int| 0 <= j < N as int ==> a1[j] == a2[j]) ==> a1 =~= a2);

// (8) The unit return value is trivially deterministic.
assert(r1 == r2);
